mapper.sql:
FROM sys_device d
LEFT JOIN sys_role r ON r.roleId = d.roleId
WHERE 1 = 1

    AND d.userId = #{userId}


    AND d.deviceId = #{deviceId}


    AND d.deviceName LIKE CONCAT('%', #{deviceName}, '%')


    AND r.roleName LIKE CONCAT('%', #{roleName}, '%')


    AND d.state = #{state}


    AND d.roleId = #{roleId}

mapper.select:
SELECT

FROM sys_code c
WHERE 1 = 1

    AND c.deviceId = #{deviceId}


    AND c.sessionId = #{sessionId}


    AND c.code = #{code}

AND c.createTime >= DATE_SUB(NOW(), INTERVAL 10 MINUTE)
ORDER BY c.createTime DESC
LIMIT 1

mapper.update:
UPDATE sys_code
SET audioPath = #{audioPath}
WHERE deviceId = #{deviceId}
  AND sessionId = #{sessionId}
  AND code = #{code}
